CREATE PROCEDURE LEADS_TEST_SUBJECT_INDEX_HOOK (inout vtb any, inout pkeyid integer)
{
  DECLARE text_to_index varchar;
  DECLARE oid any;
  text_to_index := COALESCE (
    (SELECT CONCAT (
      COALESCE (SUBJECT, ''), ' ',
      COALESCE (TITLE, ''), ' ',
      COALESCE (NAME_FIRST, '') ) FROM LEADS_TEST
    WHERE FREETEXT_ID = pkeyid), null);
  IF (text_to_index IS NULL)
    RETURN 0;
  oid := COALESCE ((SELECT ORG_ID FROM LEADS_TEST WHERE FREETEXT_ID = pkeyid), null);
  vt_batch_feed (vtb, text_to_index, 0);
  vt_batch_feed_offband (vtb, serialize (vector (oid)), 0);
  RETURN 1;
};

CREATE PROCEDURE LEADS_TEST_SUBJECT_UNINDEX_HOOK (inout vtb any, inout pkeyid integer)
{
  DECLARE text_to_index varchar;
  DECLARE oid any;
  text_to_index := COALESCE (
    (SELECT CONCAT (
      COALESCE (SUBJECT, ''), ' ',
      COALESCE (TITLE, ''), ' ',
      COALESCE (NAME_FIRST, '') ) FROM LEADS_TEST
    WHERE FREETEXT_ID = pkeyid), null);
  IF (text_to_index IS NULL)
    RETURN 0;
  oid := COALESCE ((SELECT ORG_ID FROM LEADS_TEST WHERE FREETEXT_ID = pkeyid), null);
  vt_batch_feed (vtb, text_to_index, 1);
  vt_batch_feed_offband (vtb, serialize (vector (oid)), 1);
